import { motion } from "framer-motion";

export function CTASection() {
  return (
    <section className="py-32 bg-indigo-900 border-t border-indigo-800 relative z-20 overflow-hidden text-center rounded-3xl mx-4 my-8 md:my-16 md:mx-auto max-w-7xl shadow-[0_0_50px_rgba(79,70,229,0.3)]">
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-pink-500/20 blur-[150px] rounded-full mix-blend-screen pointer-events-none" />
      <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-indigo-500/30 blur-[150px] rounded-full mix-blend-screen pointer-events-none" />

      <div className="max-w-4xl mx-auto px-6 relative z-10">
        <motion.h2
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-4xl md:text-6xl font-black mb-8 text-white tracking-tight leading-tight"
        >
          Stop Writing Docs.<br />
          Start Capturing Context.
        </motion.h2>

        <motion.div
          initial={{ opacity: 0, scale: 0.9 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          transition={{ delay: 0.2 }}
        >
          <button 
            onClick={() => window.open("#", "_blank")}
            className="px-10 py-5 text-xl font-bold text-white transition-all bg-indigo-500 rounded-2xl hover:bg-indigo-400 hover:scale-105 active:scale-95 shadow-[0_0_40px_rgba(255,255,255,0.2)] hover:shadow-[0_0_50px_rgba(255,255,255,0.4)] mb-6 flex items-center justify-center mx-auto gap-4"
          >
            👉 Install Extension Now
          </button>
        </motion.div>

        <motion.p
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ delay: 0.3 }}
          className="text-indigo-200 text-lg font-medium"
        >
          Takes less than 30 seconds to get started.
        </motion.p>
      </div>
    </section>
  );
}

import { motion } from "framer-motion";
import { Activity, Ghost, History, FileText, Lock } from "lucide-react";

export function FeaturesGrid() {
  const features = [
    {
      icon: Activity,
      title: "Logic Heatmaps",
      desc: "Understand code flow instantly. See which logical branches are executed and how data moves."
    },
    {
      icon: Ghost,
      title: "Ghost Comments",
      desc: "See past decisions, failed attempts, and deleted reasoning directly alongside standard code."
    },
    {
      icon: History,
      title: "Context Restoration",
      desc: "Resume work instantly after weekends or context switches. TRAIL rebuilds your mental model."
    },
    {
      icon: FileText,
      title: "Auto Documentation",
      desc: "Zero manual effort. TRAIL writes the “why” while you just focus on writing the “how”."
    },
    {
      icon: Lock,
      title: "Secure Context Vaults",
      desc: "Enterprise-grade storage. Your proprietary logic and codebase context is vaulted securely."
    }
  ];

  return (
    <section id="features" className="py-24 bg-slate-900 relative z-20 border-t border-slate-800">
      <div className="max-w-7xl mx-auto px-6 relative">
        <div className="text-center mb-16">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="inline-flex items-center gap-2 px-3 py-1 text-xs font-semibold rounded-full bg-indigo-950/50 border border-indigo-500/30 text-indigo-400 mb-6 uppercase tracking-wider"
          >
            Core Value
          </motion.div>
          <h2 className="text-3xl md:text-5xl font-bold mb-6 text-white tracking-tight">
            Features that Drive Productivity
          </h2>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto mb-16">
            Get context exactly when and where you need it.
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {features.map((feat, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.1 }}
              className="p-8 rounded-2xl bg-slate-900 border border-slate-800 hover:border-slate-600 transition-colors group relative overflow-hidden"
            >
              <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
              <div className="w-12 h-12 rounded-xl bg-slate-800 flex items-center justify-center mb-6 border border-slate-700 group-hover:border-indigo-500/50 transition-colors z-10 relative shadow-sm group-hover:shadow-[0_0_15px_rgba(79,70,229,0.3)]">
                <feat.icon className="w-6 h-6 text-slate-300 group-hover:text-indigo-400 transition-colors" />
              </div>
              <h3 className="text-xl font-bold text-white mb-3 z-10 relative">{feat.title}</h3>
              <p className="text-slate-400 leading-relaxed text-sm z-10 relative">
                {feat.desc}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { motion } from "framer-motion";
import { Download, Code, CheckCircle2 } from "lucide-react";

export function HowItWorks() {
  const steps = [
    { step: 1, title: "Install Extension", icon: Download, text: "Add TRAIL to your browser or IDE in seconds." },
    { step: 2, title: "Start Coding", icon: Code, text: "Work naturally. No prompts. No manual writing." },
    { step: 3, title: "Capture Done", icon: CheckCircle2, text: "TRAIL silently records logic context & decisions." }
  ];

  return (
    <section className="py-24 bg-slate-950 relative z-20 border-t border-white/5 overflow-hidden">
      <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-[500px] bg-gradient-to-b from-indigo-500/5 to-purple-500/5 blur-[120px] rounded-full pointer-events-none" />

      <div className="max-w-7xl mx-auto px-6 relative z-10">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-5xl font-bold mb-6 text-white tracking-tight">
            Install. Code. Done.
          </h2>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto mb-16">
            Integrating TRAIL takes less than 30 seconds.
          </p>
        </div>

        <div className="flex flex-col md:flex-row justify-center items-stretch gap-6 md:gap-12 relative">
          <div className="hidden md:block absolute top-[2.5rem] left-[15%] right-[15%] h-0.5 bg-gradient-to-r from-transparent via-indigo-500/30 to-transparent z-0" />

          {steps.map((step, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.2 }}
              className="flex-1 text-center relative z-10 group"
            >
              <div className="w-20 h-20 mx-auto rounded-full bg-slate-900 border border-slate-700 flex items-center justify-center mb-6  group-hover:border-indigo-500 transition-colors shadow-lg">
                <step.icon className="w-8 h-8 text-indigo-400" />
              </div>
              <h3 className="text-xl font-bold text-white mb-2">{step.title}</h3>
              <p className="text-slate-400 text-sm max-w-[200px] mx-auto leading-relaxed">
                {step.text}
              </p>
            </motion.div>
          ))}
        </div>

        <div className="mt-16 text-center">
          <button 
            onClick={() => window.open("#", "_blank")}
            className="inline-flex items-center justify-center px-8 py-4 text-base font-semibold text-white transition-all bg-indigo-600 rounded-xl hover:bg-indigo-500 shadow-[0_0_20px_rgba(79,70,229,0.4)]"
          >
            👉 Install Extension
          </button>
        </div>
      </div>
    </section>
  );
}

import { motion } from "framer-motion";
import { Check } from "lucide-react";

export function Pricing() {
  const plans = [
    {
      name: "Pulse",
      price: "Free",
      desc: "Perfect for students & individuals.",
      features: ["Basic summaries", "7-day context history", "IDE Integration", "Standard support"],
      highlight: false
    },
    {
      name: "Kinetic",
      price: "₹1999/mo",
      desc: "For small agile teams & startups.",
      features: ["Auto documentation", "Shared context vaults", "Unlimited history", "Ghost Comments", "Priority support"],
      highlight: true
    },
    {
      name: "Titanium",
      price: "Custom",
      desc: "For enterprise scale and security.",
      features: ["Dedicated context vaults", "Advanced analytics", "On-prem deployment options", "Security & compliance reporting", "SLA guarantee", "Dedicated account manager"],
      highlight: false
    }
  ];

  return (
    <section id="pricing" className="py-24 bg-slate-950 relative z-20 border-t border-slate-900/50">
      <div className="max-w-7xl mx-auto px-6 relative">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-5xl font-bold mb-6 text-white tracking-tight">
            Simple, Transparent Pricing
          </h2>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto mb-16">
            Scale your context capturing as your team grows.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          {plans.map((plan, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.1 }}
              className={`p-8 rounded-2xl border transition-all duration-300 relative ${
                plan.highlight 
                  ? "bg-slate-900 border-indigo-500 shadow-[0_0_40px_rgba(79,70,229,0.2)] scale-105 z-10" 
                  : "bg-slate-900 border-slate-800 hover:border-slate-700 opacity-90 hover:opacity-100"
              }`}
            >
              {plan.highlight && (
                <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-indigo-500 text-white px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
                  Most Popular
                </div>
              )}
              <h3 className="text-2xl font-bold text-white mb-2">{plan.name}</h3>
              <p className="text-slate-400 mb-6 min-h-[48px]">{plan.desc}</p>
              <div className="text-4xl font-black text-white mb-6 bg-clip-text">
                {plan.price}
              </div>
              <button 
                className={`w-full py-3 px-4 rounded-xl font-semibold transition-all mb-8 ${
                  plan.highlight 
                    ? "bg-indigo-600 hover:bg-indigo-500 text-white" 
                    : "bg-slate-800 hover:bg-slate-700 text-slate-300"
                }`}
              >
                {plan.highlight ? "Start Kinetic Trial" : (plan.name === "Pulse" ? "Get Started for Free" : "Contact Sales")}
              </button>

              <ul className="space-y-4">
                {plan.features.map((feature, i) => (
                  <li key={i} className="flex items-start gap-3 text-slate-300 text-sm">
                    <Check className="w-5 h-5 text-indigo-400 shrink-0" />
                    <span>{feature}</span>
                  </li>
                ))}
              </ul>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { motion } from "framer-motion";

export function ProblemSection() {
  const stats = [
    { value: "21%", label: "Developer Attrition" },
    { value: "3–6 M", label: "Onboarding Time" },
    { value: "20%", label: "Senior Engineer Time Lost" }
  ];

  return (
    <section id="problem" className="py-24 bg-[#0B0F19] relative z-20 overflow-hidden">
      {/* Decorative gradient */}
      <div className="absolute top-1/2 left-0 -translate-y-1/2 w-96 h-96 bg-red-500/10 blur-[100px] rounded-full mix-blend-screen pointer-events-none" />

      <div className="max-w-7xl mx-auto px-6 relative">
        <div className="text-center mb-16">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="inline-flex items-center gap-2 px-3 py-1 text-xs font-semibold rounded-full bg-red-950/50 border border-red-900/50 text-red-400 mb-6 uppercase tracking-wider"
          >
            The Business Reality
          </motion.div>

          <h2 className="text-3xl md:text-5xl font-bold mb-6 text-white tracking-tight leading-tight">
            The Cost of Missing Context
          </h2>
          <p className="text-xl text-slate-400 max-w-2xl mx-auto italic">
            "Companies don’t lose code — they lose understanding."
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          {stats.map((stat, idx) => (
            <motion.div
              key={idx}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.15 }}
              className="p-8 rounded-2xl bg-gradient-to-br from-slate-900/80 to-slate-900/20 border border-red-900/20 hover:border-red-900/40 transition-colors text-center shadow-lg"
            >
              <div className="text-6xl font-black mb-4 text-transparent bg-clip-text bg-gradient-to-b from-red-400 to-red-600/50">
                {stat.value}
              </div>
              <div className="text-slate-300 font-medium tracking-wide">
                {stat.label}
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { motion } from "framer-motion";
import { TerminalSquare, BrainCircuit, Database } from "lucide-react";

export function ProductIntro() {
  const steps = [
    {
      icon: TerminalSquare,
      title: "1. Developer writes code",
      desc: "Code naturally. TRAIL stays out of your way in the background."
    },
    {
      icon: BrainCircuit,
      title: "2. TRAIL captures intent",
      desc: "It tracks logical paths, dead-ends, and reasoning automatically."
    },
    {
      icon: Database,
      title: "3. Context is stored securely",
      desc: "Everything becomes a searchable 'digital exhaust' knowledge base."
    }
  ];

  return (
    <section id="product" className="py-24 bg-slate-900 border-t border-slate-800 relative z-20">
      <div className="max-w-7xl mx-auto px-6 relative">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-5xl font-bold mb-6 text-white tracking-tight">
            What is TRAIL?
          </h2>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto mb-16">
            TRAIL is a <strong className="text-slate-200">passive context-capturing system</strong>. 
            It works silently via a browser and IDE extension, converting your daily coding "digital exhaust" into structured, searchable knowledge.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 relative">
          <div className="hidden md:block absolute top-[28%] left-[16%] right-[16%] h-[2px] bg-gradient-to-r from-indigo-500/20 via-purple-500/50 to-pink-500/20 z-0" />

          {steps.map((step, idx) => (
            <motion.div 
              key={idx}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: idx * 0.2 }}
              className="relative z-10 glass p-8 rounded-2xl flex flex-col items-center text-center group hover:-translate-y-2 transition-transform duration-300"
            >
              <div className="w-16 h-16 rounded-full bg-slate-800 border-2 border-slate-700 flex items-center justify-center mb-6 group-hover:border-indigo-500 transition-colors bg-slate-900 shadow-[0_0_15px_rgba(0,0,0,0.5)]">
                <step.icon className="w-8 h-8 text-indigo-400" />
              </div>
              <h3 className="text-xl font-bold text-white mb-3">{step.title}</h3>
              <p className="text-slate-400 leading-relaxed text-sm">
                {step.desc}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

